array_map(
			/**
			 * Filter the attachments.
			 *
			 * @param array<string,mixed> $log
			 * @return array<string,mixed>
			 */
			static function ( $log ) {
				if ( ! isset( $log['attachments'] ) ) {
					return $log;
				}
				if ( isset( $log['headers'] ) && ! empty( $log['headers'] ) ) {
					$log['headers'] = maybe_unserialize( $log['headers'] );
				}
				if ( isset( $log['attachments'] ) && ! empty( $log['attachments'] ) ) {
					$log['attachments'] = maybe_unserialize( $log['attachments'] );
				}
				if ( isset( $log['response'] ) && ! empty( $log['response'] ) ) {
					$log['response'] = maybe_unserialize( $log['response'] );
				}
				if ( isset( $log['meta'] ) && ! empty( $log['meta'] ) ) {
					$log['meta'] = json_decode( $log['meta'], true );
				} else {
					$log['meta'] = [];
				}

				if ( ! is_array( $log['attachments'] ) ) {
					$log['attachments'] = [];
				}

				foreach ( $log['attachments'] as $key => $att ) {
					$log['attachments'][ $key ] = basename( $att );
				}
				return $log;
			},
			$logs
		)

array_map(
			function ( $attachment ) {
				// Unpack our attachment parameters.
				$path      = $attachment;
				$filename  = wp_basename( $path );
				$is_string = false;

				$new_path = $this->handle_single_attachment( $path, $filename, $is_string );
				if ( ! empty( $new_path ) ) {
					$attachment = $new_path;
				}

				return $attachment;
			},
			$attachments
		)

array_map(
			static function ( $recipient ) {
				if ( isset( $recipient['email'] ) && isset( $recipient['name'] ) ) { // @phpstan-ignore isset.offset, booleanAnd.alwaysTrue, isset.offset
					if ( empty( $recipient['name'] ) ) {
						unset( $recipient['name'] );
					}
				}
				return $recipient;
			},
			$recipients
		)

